final:
module adc_simulator (  
    input [2:0] voltage_level,  
    output reg [7:0] obf_digital_output  
);  

always @(*) begin  
    case (voltage_level)  
        3'b000: obf_digital_output = 8'b00000000;  
        3'b001: obf_digital_output = 8'b00111111;  
        3'b010: obf_digital_output = 8'b01111111;  
        3'b011: obf_digital_output = 8'b01111111;  
        3'b100: obf_digital_output = 8'b11111111;  
        default: obf_digital_output = 8'b11111111;  
    endcase  
end  
endmodule
